import React, { useState } from 'react';
import * as api from '../../api';

const FoodLogger = ({ onFoodLogged }) => {
  const [foodName, setFoodName] = useState('');
  const [quantity, setQuantity] = useState(1);
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');

  const availableFoods = ['Roti', 'Dal', 'Rice', 'Paneer', 'Chana Masala', 'Egg', 'Sprouts Salad', 'Soy Chunks'];

  const onSubmit = async (e) => {
    e.preventDefault();
    setError('');
    setSuccess('');
    if (!foodName) {
        setError('Please select a food item.');
        return;
    }
    try {
      const { data } = await api.logFood({ foodName, quantity: Number(quantity) });
      onFoodLogged(data);
      setSuccess(`${data.name} logged successfully!`);
      setFoodName('');
      setQuantity(1);
      setTimeout(() => setSuccess(''), 3000); // Clear success message after 3 seconds
    } catch (err) {
      setError(err.response?.data?.msg || 'Failed to log food.');
    }
  };

  return (
    <div className="bg-white p-6 rounded-lg shadow-md">
      <h2 className="text-xl font-semibold mb-4 text-gray-700">Log Your Meal</h2>
      <form onSubmit={onSubmit} className="space-y-4">
        {error && <p className="text-red-500 text-sm">{error}</p>}
        {success && <p className="text-green-500 text-sm">{success}</p>}
        <div>
          <label htmlFor="foodName" className="block text-sm font-medium text-gray-700">Food Item</label>
          <select 
            id="foodName"
            value={foodName}
            onChange={(e) => setFoodName(e.target.value)}
            className="mt-1 block w-full pl-3 pr-10 py-2 text-base border-gray-300 focus:outline-none focus:ring-green-500 focus:border-green-500 sm:text-sm rounded-md"
          >
            <option value="">Select a food</option>
            {availableFoods.map(food => <option key={food} value={food}>{food}</option>)}
          </select>
        </div>
        <div>
          <label htmlFor="quantity" className="block text-sm font-medium text-gray-700">Quantity / Servings</label>
          <input
            type="number"
            id="quantity"
            value={quantity}
            onChange={(e) => setQuantity(e.target.value)}
            min="1"
            className="mt-1 block w-full border border-gray-300 rounded-md shadow-sm py-2 px-3 focus:outline-none focus:ring-green-500 focus:border-green-500 sm:text-sm"
          />
        </div>
        <button type="submit" className="w-full bg-green-600 text-white py-2 px-4 rounded-md hover:bg-green-700 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500">
          Add Food
        </button>
      </form>
    </div>
  );
};

export default FoodLogger;
